-- ═══════════════════════════════════════════════════════════════════════════
-- ETHICARA — California Medical Board (CCR Title 16, Division 13)
-- ═══════════════════════════════════════════════════════════════════════════

-- Medical Practice Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_060', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Bus. & Prof. Code §§ 2000-2529 (Medical Practice Act)', 'BPC §§ 2000-2529', 'Medical Practice Act — Physician Licensure and Regulation', 'Comprehensive statutory framework governing the practice of medicine in California. Establishes the Medical Board of California, defines the practice of medicine, sets licensure requirements, establishes grounds for disciplinary action, and authorizes enforcement mechanisms including license revocation, suspension, and probation. Unlicensed practice of medicine is a felony under BPC § 2052.', '["Licensed physician required for practice of medicine (§ 2052)","Graduation from approved medical school required (§ 2089)","Completion of USMLE or equivalent examination (§ 2170-2178)","Postgraduate training — minimum 1 year ACGME-accredited (§ 2096)","License renewal every 2 years with continuing medical education (§ 2420)","Mandatory reporting of malpractice judgments and settlements over $30,000 (§ 801.01)","Hospital peer review reporting to Medical Board (§ 805)","Physician must maintain adequate records (§ 2266)","Prohibition on fee splitting and referral fees (§ 650)","Prohibition on sexual contact with patients (§ 726)","Mandatory reporting of physician impairment (§ 2290.5)"]', '[{"section":"2052","description":"Unlicensed practice — felony; defines practice of medicine"},{"section":"2089-2091","description":"Medical school and education requirements for licensure"},{"section":"2170-2178","description":"Examination requirements — USMLE or equivalent"},{"section":"2096","description":"Postgraduate training requirements — ACGME accreditation"},{"section":"2220-2220.05","description":"Unprofessional conduct — general grounds for discipline"},{"section":"2234","description":"Unprofessional conduct enumerated — incompetence, gross negligence, repeated negligent acts, dishonesty/corruption"},{"section":"2266","description":"Failure to maintain adequate and accurate medical records"},{"section":"726","description":"Sexual misconduct with patient — automatic revocation"},{"section":"805","description":"Peer review reporting — 805 reports to Medical Board"},{"section":"801.01","description":"Malpractice settlement/judgment reporting requirements"},{"section":"2420","description":"License renewal and continuing medical education"}]', '["medical_license_application","disciplinary_complaint","805_peer_review_report","malpractice_settlement_report","CME_documentation","license_renewal","accusation_filing","statement_of_issues"]', '["professional-ethics-standards-audit"]', 'Medical Board of California (MBC)', 0, 1, datetime('now'), datetime('now'));

-- Physician Reporting Duties — Injuries
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_061', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Penal Code §§ 11160-11163.6', 'PC §§ 11160-11163.6', 'Physician Mandatory Reporting — Injuries by Firearm, Assault, or Abuse', 'Requires health practitioners to report to local law enforcement when they provide treatment for injuries inflicted by a firearm, assaultive or abusive conduct, or when the injury is the result of a criminal act. Reports must be made immediately or as soon as practically possible by telephone and followed by a written report within two business days. Failure to report is a misdemeanor under PC § 11162.', '["Immediate telephone report to local law enforcement required","Written report within 2 business days of providing treatment","Must report firearm injuries — all gunshot wounds (§ 11160(a))","Must report injuries from assaultive or abusive conduct (§ 11160(b))","Must report injuries resulting from criminal acts","Report must include patient name, location, nature of injuries, identity of alleged perpetrator if known","Health practitioner includes physicians, surgeons, nurses, EMTs, dentists","Failure to report is a misdemeanor (§ 11162)","Immunity from civil/criminal liability for good faith reports (§ 11161.9)","Does not require patient consent to make report"]', '[{"section":"11160(a)","description":"Mandatory report of firearm injuries"},{"section":"11160(b)","description":"Mandatory report of assaultive/abusive conduct injuries"},{"section":"11160(c)","description":"Immediate telephone report to law enforcement"},{"section":"11161(a)","description":"Written report within 2 business days"},{"section":"11161.8","description":"Report form prescribed by Office of Emergency Services"},{"section":"11161.9","description":"Immunity from liability for good faith reporting"},{"section":"11162","description":"Failure to report — misdemeanor penalty"},{"section":"11163.6","description":"Confidentiality of reports"}]', '["injury_report_form","law_enforcement_notification","medical_records","emergency_department_records","OES_reporting_form"]', '["professional-ethics-standards-audit"]', 'Local Law Enforcement / District Attorney', 0, 1, datetime('now'), datetime('now'));

-- Mandatory Child Abuse Reporting (CANRA)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_062', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Penal Code §§ 11164-11174.3 (CANRA — Child Abuse and Neglect Reporting Act)', 'PC §§ 11164-11174.3', 'Child Abuse and Neglect Reporting Act (CANRA) — Mandatory Reporter Obligations', 'CANRA designates physicians, psychologists, therapists, teachers, social workers, clergy, and dozens of other professionals as mandated reporters who must report known or reasonably suspected child abuse or neglect. Reports go to county child protective services or law enforcement. Failure to report is a misdemeanor with up to 6 months jail and $1,000 fine. Reporter immunity from civil/criminal liability for good faith reports.', '["Mandated reporter must report immediately or as soon as practically possible by telephone","Written follow-up report (SS 8572) within 36 hours of telephone report","Report to county child welfare department or local law enforcement","Reasonable suspicion standard — not certainty required (§ 11166(a))","Child abuse includes physical abuse, sexual abuse, neglect, willful cruelty, emotional abuse, exploitation","Mandated reporters include physicians, psychologists, therapists, nurses, dentists, teachers, social workers, peace officers, clergy (§ 11165.7)","Failure to report: misdemeanor, up to 6 months jail and $1,000 fine (§ 11166(c))","Civil liability for damages caused by failure to report (§ 11172(e))","Good faith reporter immunity from civil and criminal liability (§ 11172(a))","Employer may not retaliate against employee for making report (§ 11166(f))","Confidentiality of reporter identity (§ 11167(d))"]', '[{"section":"11165.1-11165.6","description":"Definitions — child abuse, neglect, sexual abuse, exploitation"},{"section":"11165.7","description":"Mandated reporter categories — 46+ professional categories"},{"section":"11166(a)","description":"Duty to report — reasonable suspicion standard"},{"section":"11166(c)","description":"Failure to report — misdemeanor penalty"},{"section":"11167","description":"Telephone and written report requirements — SS 8572 form"},{"section":"11167(d)","description":"Confidentiality of reporter identity"},{"section":"11170","description":"Child Abuse Central Index (CACI) — DOJ maintained"},{"section":"11172(a)","description":"Immunity from liability for good faith reports"},{"section":"11172(e)","description":"Civil liability for failure to report — damages proximately caused"},{"section":"11174.3","description":"Penalties for false reports of child abuse"}]', '["SS_8572_report","CACI_notification","CPS_referral","law_enforcement_report","medical_examination_report","forensic_interview_record","mandated_reporter_training_certificate"]', '["professional-ethics-standards-audit"]', 'County Child Welfare Services / Law Enforcement / DOJ (CACI)', 1, 1, datetime('now'), datetime('now'));

-- Elder/Dependent Adult Abuse Reporting
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_063', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code §§ 15630-15632 (Elder Abuse Reporting)', 'WIC §§ 15630-15632', 'Mandatory Reporting of Elder and Dependent Adult Abuse', 'Mandated reporters (health practitioners, care custodians, clergy, and specified others) must report known or suspected abuse of elders (65+) or dependent adults to Adult Protective Services (APS) or local law enforcement. Abuse includes physical, sexual, financial, neglect, abandonment, isolation, abduction, and mental suffering. Immediate telephone report required, written follow-up within 2 working days.', '["Immediate telephone report to APS or law enforcement","Written report (SOC 341) within 2 working days","Elder defined as person aged 65 or older (§ 15610.27)","Dependent adult defined as person 18-64 with qualifying disabilities (§ 15610.23)","Abuse types: physical, sexual, financial, neglect, abandonment, isolation, abduction, mental suffering","Mandated reporters include health practitioners, care custodians, clergy, financial institution employees (§ 15630)","Failure to report: misdemeanor, up to 6 months jail and $1,000 fine (§ 15630(h))","If death or great bodily injury results from failure to report: up to 1 year jail and $5,000 fine","Good faith reporter immunity (§ 15634)","Financial abuse reporting by banks and financial institutions (§ 15630.1)"]', '[{"section":"15610.07","description":"Abuse defined — physical, sexual, neglect, financial, isolation, abandonment"},{"section":"15610.23","description":"Dependent adult defined — 18-64 with qualifying disabilities"},{"section":"15610.27","description":"Elder defined — person aged 65 or older"},{"section":"15610.30","description":"Financial abuse defined — taking property by undue influence, fraud, duress"},{"section":"15630(a)","description":"Mandated reporter duty — immediate telephone report"},{"section":"15630(b)","description":"Written follow-up report within 2 working days — SOC 341"},{"section":"15630(h)","description":"Failure to report — misdemeanor penalty"},{"section":"15630.1","description":"Financial institution reporting of suspected financial abuse"},{"section":"15631","description":"Report to APS for community; ombudsman for long-term care"},{"section":"15634","description":"Immunity for good faith reporters"}]', '["SOC_341_report","APS_referral","law_enforcement_report","ombudsman_complaint","financial_abuse_report","medical_examination_record","care_facility_incident_report"]', '["professional-ethics-standards-audit"]', 'Adult Protective Services (APS) / Long-Term Care Ombudsman / Law Enforcement', 1, 1, datetime('now'), datetime('now'));

-- Standard of Care — Medical Malpractice (MICRA)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_064', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Code Civ. Proc. § 340.5; Cal. Civ. Code § 3333.2 (MICRA)', 'CCP § 340.5 / CC § 3333.2', 'Standard of Care and Medical Malpractice — MICRA Framework', 'California medical malpractice governed by Medical Injury Compensation Reform Act (MICRA, 1975, amended by Prop 35/AB 35, 2022). Statute of limitations: 1 year from discovery or 3 years from injury, whichever is first (CCP § 340.5). Noneconomic damages capped at $350,000 for non-death cases (increasing annually) and $500,000 for wrongful death (increasing annually) under AB 35 amendments effective 1/1/2023. Standard of care: that degree of skill, knowledge, and care ordinarily possessed by a reasonably competent practitioner in the same field under similar circumstances.', '["Standard of care: skill and knowledge of reasonably competent practitioner in same field","Statute of limitations: 1 year from discovery or 3 years from injury (CCP § 340.5)","Discovery rule: SOL runs from when patient discovers or should have discovered injury","Tolling for fraud, concealment, and presence of foreign body","MICRA noneconomic damage cap: $350,000 non-death / $500,000 death (2023 base, increasing annually)","90-day notice of intent to sue required before filing (CCP § 364)","Expert declaration required with complaint (CCP § 411.35)","Periodic payments for future damages over $50,000 (CCP § 667.7)","Attorney fee cap: sliding scale 40%/33%/25%/15% (BPC § 6146)","Collateral source payments admissible (CC § 3333.1)"]', '[{"section":"CCP 340.5","description":"Statute of limitations — 1 year discovery / 3 years injury"},{"section":"CCP 364","description":"90-day notice of intent to sue — prelitigation requirement"},{"section":"CC 3333.2","description":"MICRA noneconomic damage cap — $350K non-death / $500K death (2023 base)"},{"section":"CC 3333.1","description":"Collateral source rule — payments admissible to reduce damages"},{"section":"CCP 667.7","description":"Periodic payments for future damages exceeding $50,000"},{"section":"BPC 6146","description":"Attorney fee cap — sliding scale on recovery"},{"section":"CCP 411.35","description":"Expert certificate of merit required with complaint"},{"section":"BPC 801.01","description":"Reporting requirement — settlements/judgments over $30,000 to MBC"}]', '["notice_of_intent_to_sue","medical_malpractice_complaint","expert_declaration","medical_records","standard_of_care_analysis","damages_calculation","settlement_agreement","MBC_801_report"]', '["professional-ethics-standards-audit"]', 'California Superior Court / Medical Board of California', 1, 1, datetime('now'), datetime('now'));

-- Informed Consent
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_065', 'ETHICARA', 'CASE_LAW', 'CA', 'Cobbs v. Grant (1972) 8 Cal.3d 229; Cal. Civ. Code § 3294; Cal. Health & Safety Code § 1690', 'Cobbs v. Grant / CC § 3294', 'Informed Consent — Physician Duty to Disclose Risks and Alternatives', 'California follows the patient-centered standard of informed consent established in Cobbs v. Grant (1972). Physician must disclose all material information a reasonable patient would want to know to make an informed decision, including diagnosis, nature of proposed treatment, risks and benefits, alternative treatments and their risks, and prognosis if treatment is declined. Failure to obtain informed consent constitutes negligence, not battery (unless no consent at all).', '["Physician must disclose diagnosis and condition","Must disclose nature of proposed treatment or procedure","Must disclose material risks of proposed treatment","Must disclose benefits and probability of success","Must disclose alternative treatments and their risks","Must disclose prognosis if patient declines treatment","Patient-centered standard: what a reasonable patient would want to know (Cobbs v. Grant)","Exceptions: emergency, patient waiver, therapeutic privilege (narrowly construed)","Causation: would a reasonable person in patient position have declined treatment","Lack of informed consent is negligence, not battery (Cobbs)","Written consent required for certain procedures (H&S § 1690)","Punitive damages available for conscious disregard of patient safety (CC § 3294)"]', '[{"section":"Cobbs v. Grant, 8 Cal.3d 229 (1972)","description":"Established patient-centered informed consent standard in California"},{"section":"Arato v. Avedon, 5 Cal.4th 1172 (1993)","description":"No duty to disclose statistical life expectancy — material risk standard applies"},{"section":"Truman v. Thomas, 27 Cal.3d 285 (1980)","description":"Duty to inform of risks of REFUSING recommended treatment"},{"section":"H&S § 1690","description":"Written consent required for specified surgical procedures"},{"section":"CC § 3294","description":"Punitive damages for malice, oppression, or fraud"},{"section":"BPC § 2397","description":"Informed consent for experimental treatments and clinical trials"}]', '["informed_consent_form","surgical_consent","treatment_authorization","AMA_discharge_form","medical_records","risk_disclosure_documentation","patient_refusal_form"]', '["professional-ethics-standards-audit"]', 'California Superior Court', 1, 1, datetime('now'), datetime('now'));

-- Medical Board Disciplinary Actions
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_066', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Bus. & Prof. Code §§ 2220-2320 (Medical Board Discipline)', 'BPC §§ 2220-2320', 'Medical Board Disciplinary Actions — Physician Misconduct and Enforcement', 'The Medical Board of California may revoke, suspend, or place conditions on a physician license for unprofessional conduct. Grounds include gross negligence, repeated negligent acts, incompetence, dishonesty/corruption, prescribing violations, conviction of crime substantially related to practice, sexual misconduct, and mental/physical illness affecting competency. Disciplinary process: complaint, investigation, accusation (AG files), ALJ hearing (OAH), Board decision. Physician may petition for reinstatement after specified period.', '["Gross negligence — single act of extreme departure from standard of care (§ 2234(b))","Repeated negligent acts — pattern establishing incompetence (§ 2234(c))","Incompetence — lack of knowledge or skill in discharging professional obligations (§ 2234(d))","Dishonesty or corruption (§ 2234(e))","Conviction of crime substantially related to duties (§ 2236)","Self-prescribing controlled substances (§ 2238)","Sexual misconduct with patient — grounds for automatic revocation (§ 726)","Mental/physical illness affecting competency (§ 2239)","Excessive prescribing of controlled substances (§ 2242)","Aiding unlicensed practice of medicine (§ 2264)","Violation of probation terms (§ 2306)","Interim suspension order for public protection (§ 2311)"]', '[{"section":"2220-2220.05","description":"Board authority — protection of public paramount concern"},{"section":"2227","description":"Revocation or suspension for unprofessional conduct"},{"section":"2228","description":"Probation — terms and conditions"},{"section":"2234","description":"Unprofessional conduct defined — gross negligence, repeated negligence, incompetence, dishonesty"},{"section":"2236","description":"Criminal conviction as grounds for discipline"},{"section":"2238-2242","description":"Prescribing violations — controlled substances"},{"section":"726","description":"Sexual misconduct — automatic revocation"},{"section":"2290.5","description":"Physician wellness/impairment program"},{"section":"2305-2307","description":"Probation violation and enforcement"},{"section":"2311","description":"Interim suspension order — imminent danger to public"},{"section":"2307","description":"Petition for reinstatement of revoked license"}]', '["accusation_filing","statement_of_issues","OAH_decision","Board_decision_order","stipulated_settlement","probation_order","interim_suspension_order","reinstatement_petition","805_peer_review_report","complaint_to_MBC"]', '["professional-ethics-standards-audit"]', 'Medical Board of California / Attorney General / Office of Administrative Hearings', 0, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- ETHICARA — Psychiatric / Psychological Standards
-- ═══════════════════════════════════════════════════════════════════════════

-- Psychotherapist-Patient Privilege
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_067', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Evidence Code §§ 1010-1027 (Psychotherapist-Patient Privilege)', 'Evid. Code §§ 1010-1027', 'Psychotherapist-Patient Privilege — Confidential Communications', 'California statutory privilege protecting confidential communications between patient and psychotherapist. Psychotherapist includes psychiatrists, licensed psychologists, licensed clinical social workers, MFTs, and LPCCs. Patient holds the privilege and may prevent disclosure in judicial proceedings. Exceptions include dangerous patient (Tarasoff), child abuse reporting, court-ordered examination, patient-litigant exception, and proceedings to hospitalize patient.', '["Patient holds the privilege — may refuse to disclose and prevent others from disclosing (§ 1014)","Psychotherapist includes psychiatrists, psychologists, LCSWs, MFTs, LPCCs, trainees under supervision (§ 1010)","Confidential communication: information transmitted in confidence during course of treatment (§ 1012)","Privilege survives death of patient — representative may claim (§ 1013)","Psychotherapist has duty to claim privilege on patient behalf unless instructed otherwise (§ 1015)","Exception: dangerous patient — duty to warn/protect (§ 1024 + Tarasoff)","Exception: patient puts mental condition in issue — patient-litigant (§ 1016)","Exception: court-ordered examination — no privilege (§ 1017)","Exception: child abuse/elder abuse mandatory reporting overrides privilege","Exception: proceeding to commit patient (§ 1024)","Exception: patient is minor and therapist believes disclosure necessary to prevent harm (§ 1027)"]', '[{"section":"1010","description":"Psychotherapist defined — psychiatrists, psychologists, LCSWs, MFTs, LPCCs"},{"section":"1012","description":"Confidential communication defined — information transmitted in confidence"},{"section":"1013","description":"Patient defined — person who consults psychotherapist for treatment"},{"section":"1014","description":"Privilege of patient — may refuse to disclose and prevent disclosure"},{"section":"1015","description":"Psychotherapist duty to claim privilege absent patient instruction"},{"section":"1016","description":"Patient-litigant exception — patient puts mental condition in issue"},{"section":"1017","description":"Court-ordered examination exception"},{"section":"1024","description":"Dangerous patient exception — risk of harm to self or others"},{"section":"1025","description":"Proceeding to establish patient competence"},{"section":"1027","description":"Minor patient — therapist believes disclosure prevents harm"}]', '["subpoena_response","privilege_log","motion_to_quash","therapy_records","court_order_for_examination","patient_authorization_release","objection_to_disclosure"]', '["professional-ethics-standards-audit"]', 'California Superior Court', 0, 1, datetime('now'), datetime('now'));

-- Tarasoff Duty to Warn/Protect
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_068', 'ETHICARA', 'CASE_LAW', 'CA', 'Tarasoff v. Regents of University of California (1976) 17 Cal.3d 425; Cal. Civ. Code § 43.92', 'Tarasoff / CC § 43.92', 'Tarasoff Duty to Warn and Protect — Therapist Obligation to Identifiable Victims', 'Landmark California Supreme Court decision establishing that a psychotherapist who determines, or pursuant to professional standards reasonably should determine, that a patient presents a serious danger of violence to a reasonably identifiable victim has a duty to use reasonable efforts to protect the intended victim. Codified and limited by CC § 43.92: duty discharged by making reasonable efforts to communicate the threat to the victim and to a law enforcement agency. Failure creates civil liability for resulting harm.', '["Duty arises when therapist determines or should determine patient poses serious danger of violence","Victim must be reasonably identifiable — not general threats to public","Duty discharged by reasonable efforts to communicate threat to victim AND law enforcement (§ 43.92(b))","Applies to psychiatrists, psychologists, LCSWs, MFTs, LPCCs, and trainees","Standard: what a reasonable therapist would determine under professional standards","No duty for general predictions of dangerousness without identifiable victim","Overrides psychotherapist-patient privilege (Evid. Code § 1024)","Civil liability for failure to warn/protect when duty exists","No criminal penalty — civil tort liability only","Good faith effort to warn satisfies duty even if warning does not reach victim"]', '[{"section":"Tarasoff I (1974)","description":"Original duty to warn — must warn identifiable victim"},{"section":"Tarasoff II (1976) 17 Cal.3d 425","description":"Expanded to duty to protect — reasonable steps to protect victim"},{"section":"CC § 43.92(a)","description":"No monetary liability for failure to warn UNLESS § 43.92(b) duty applies"},{"section":"CC § 43.92(b)","description":"Duty: reasonable efforts to communicate threat to victim AND law enforcement"},{"section":"Thompson v. County of Alameda (1980) 27 Cal.3d 741","description":"No duty for general threats — victim must be identifiable"},{"section":"Hedlund v. Superior Court (1983) 34 Cal.3d 695","description":"Duty extends to foreseeable persons in close relationship with victim"},{"section":"Evid. Code § 1024","description":"Dangerous patient exception to psychotherapist-patient privilege"}]', '["Tarasoff_warning_letter","law_enforcement_notification","threat_assessment_documentation","clinical_notes","patient_safety_plan","risk_assessment_form","victim_notification_record"]', '["professional-ethics-standards-audit"]', 'California Superior Court', 1, 1, datetime('now'), datetime('now'));

-- LPS Act — Involuntary Hold (5150)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_069', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code §§ 5150-5157 (LPS Act — 72-Hour Hold)', 'WIC §§ 5150-5157', 'Lanterman-Petris-Short Act — Involuntary Psychiatric Hold (5150)', 'Authorizes designated professionals (peace officers, designated mental health professionals) to involuntarily detain a person for up to 72 hours for psychiatric evaluation and treatment when there is probable cause to believe the person is a danger to self, danger to others, or gravely disabled due to a mental health disorder. Patient has right to habeas corpus, right to refuse medication (except emergency), right to communicate with attorney and patients'' rights advocate. County-designated facilities only.', '["72-hour maximum initial hold for evaluation and treatment","Probable cause standard: danger to self, danger to others, or gravely disabled","Only authorized persons may initiate: peace officers, designated staff of county evaluation facilities (§ 5150)","Detention only at county-designated 5150 facility","Patient must be advised of rights upon admission (§ 5157)","Right to habeas corpus — immediate judicial review (§ 5275)","Right to communicate with patients rights advocate","Right to refuse medication except in emergency (Riese v. St. Mary Hospital)","Must be released before 72 hours if criteria no longer met","May be extended to 14-day certification (§ 5250) if criteria persist","Application for 5150 must document specific facts — not conclusory statements","Gravely disabled: unable to provide for food, clothing, or shelter due to mental disorder (§ 5008(h))"]', '[{"section":"5150","description":"72-hour detention authority — danger to self, others, or gravely disabled"},{"section":"5150.05","description":"Persons authorized to take into custody — peace officers, designated professionals"},{"section":"5151","description":"Application for 72-hour detention — written statement of facts"},{"section":"5152","description":"Assessment at designated facility within 36 hours"},{"section":"5154","description":"Release required when criteria no longer met"},{"section":"5157","description":"Patient rights advisement upon admission"},{"section":"5008(h)","description":"Gravely disabled defined — unable to provide food, clothing, shelter"},{"section":"5250","description":"14-day certification for intensive treatment (extension)"},{"section":"5275-5276","description":"Habeas corpus — right to judicial review of detention"}]', '["5150_application","psychiatric_evaluation","patients_rights_notification","habeas_corpus_petition","certification_review_hearing","discharge_plan","clinical_assessment","medication_consent_or_refusal"]', '["professional-ethics-standards-audit"]', 'County Mental Health Department / California Superior Court', 1, 1, datetime('now'), datetime('now'));

-- LPS Act — Conservatorship
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_070', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code §§ 5350-5372 (LPS Conservatorship)', 'WIC §§ 5350-5372', 'LPS Conservatorship — Involuntary Treatment of Gravely Disabled Persons', 'LPS conservatorship provides court-appointed conservator for persons determined to be gravely disabled due to mental health disorder — unable to provide for food, clothing, or shelter. More restrictive than Probate conservatorship. Requires beyond-a-reasonable-doubt finding of grave disability. Initial term one year, renewable. Conservatee retains rights not specifically removed by court. Conservatee has right to jury trial on reappointment. County public guardian or designated agency typically serves as conservator.', '["Person must be gravely disabled — unable to provide food, clothing, or shelter due to mental disorder (§ 5008(h))","Beyond a reasonable doubt standard at hearing (§ 5350)","Right to jury trial on conservatorship and reappointment (§ 5350(d))","Initial conservatorship term: 1 year (§ 5361)","Renewable annually upon showing continued grave disability (§ 5362)","Conservatee retains all rights not specifically removed by court order","Right to counsel — public defender or appointed attorney (§ 5365)","Conservator must be least restrictive appropriate placement","Conservator may authorize involuntary medication (Riese rights waived by court)","Court may grant specific additional powers: medical decisions, placement (§ 5357)","Temporary conservatorship available pending hearing (§ 5352.1) — 30 days","Conservatee may petition for termination at any time (§ 5364)"]', '[{"section":"5350","description":"Establishment of conservatorship — gravely disabled finding required"},{"section":"5350(d)","description":"Right to jury trial — beyond a reasonable doubt standard"},{"section":"5352","description":"Petition for appointment of conservator — county initiated"},{"section":"5352.1","description":"Temporary conservatorship — 30 days pending hearing"},{"section":"5357","description":"Powers of conservator — placement, medical, financial decisions"},{"section":"5358","description":"Placement in least restrictive appropriate setting"},{"section":"5361","description":"One-year duration of conservatorship"},{"section":"5362","description":"Reappointment — annual renewal upon continued grave disability"},{"section":"5364","description":"Conservatee right to petition for termination"},{"section":"5365","description":"Right to counsel — public defender appointment"},{"section":"5370-5372","description":"Additional powers — involuntary medication, ECT, locked facilities"}]', '["conservatorship_petition","capacity_declaration","court_investigator_report","treatment_plan","annual_status_report","jury_trial_demand","petition_for_termination","temporary_conservatorship_order","placement_order","Riese_hearing_order"]', '["professional-ethics-standards-audit"]', 'California Superior Court (Probate Division) / County Public Guardian', 1, 1, datetime('now'), datetime('now'));

-- Competency to Stand Trial
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_071', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Penal Code §§ 1367-1376 (Competency to Stand Trial)', 'PC §§ 1367-1376', 'Competency to Stand Trial — Mental Competence Proceedings', 'A defendant is mentally incompetent to stand trial if, as a result of a mental health disorder or developmental disability, the defendant is unable to understand the nature of the criminal proceedings or to assist counsel in a rational manner. When doubt arises, court must declare a doubt and suspend criminal proceedings. Defendant evaluated by court-appointed experts. If found incompetent, committed to treatment facility (state hospital or outpatient) to restore competency. Maximum commitment cannot exceed the maximum sentence for the charged offense.', '["Competency standard: ability to understand proceedings AND assist counsel rationally (§ 1367)","Court must declare doubt sua sponte or on motion when substantial evidence of incompetence (§ 1368)","Criminal proceedings suspended upon declaration of doubt","Court appoints psychiatrist or psychologist to evaluate defendant (§ 1369)","Jury trial available on competency question (§ 1369(a))","Preponderance of evidence standard — defendant presumed competent","If incompetent: commitment to state hospital or outpatient program for restoration (§ 1370)","Maximum commitment: 3 years or maximum sentence, whichever is less (§ 1370(c))","Misdemeanor incompetence: maximum commitment is the misdemeanor sentence (§ 1370.01)","If competency not restorable: Murphy conservatorship or charges dismissed (§ 1370(a)(1)(H))","Defendant may not be medicated involuntarily solely to restore competency without Sell hearing","Periodic reports to court on progress toward competency restoration (§ 1372)"]', '[{"section":"1367","description":"Mental incompetence defined — understand proceedings and assist counsel"},{"section":"1368","description":"Declaration of doubt — court duty to suspend proceedings"},{"section":"1369","description":"Hearing on competency — expert evaluation, jury trial available"},{"section":"1370","description":"Commitment for treatment if found incompetent — state hospital or outpatient"},{"section":"1370(a)(1)(H)","description":"Nonrestorable — Murphy conservatorship or dismissal"},{"section":"1370(c)","description":"Maximum commitment — 3 years or max sentence, whichever less"},{"section":"1370.01","description":"Misdemeanor incompetence — commitment limited to misdemeanor term"},{"section":"1372","description":"Certification of restoration — return to criminal proceedings"},{"section":"1375","description":"Effect of medication on competency — court consideration"},{"section":"Sell v. United States (2003) 539 U.S. 166","description":"Involuntary medication for competency restoration — federal constitutional standard"}]', '["competency_evaluation_report","court_order_suspending_proceedings","commitment_order","restoration_progress_report","certificate_of_competency","Murphy_conservatorship_petition","expert_declaration","Sell_hearing_motion"]', '["professional-ethics-standards-audit"]', 'California Superior Court (Criminal Division) / Department of State Hospitals', 0, 1, datetime('now'), datetime('now'));

-- ABPN Board Certification Standards
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_072', 'ETHICARA', 'PROFESSIONAL_STANDARD', 'US', 'American Board of Psychiatry and Neurology (ABPN) — Certification Requirements', 'ABPN Certification', 'ABPN Board Certification — Psychiatry and Forensic Psychiatry Standards', 'The American Board of Psychiatry and Neurology (ABPN) is the ABMS member board certifying physicians in psychiatry, neurology, and subspecialties. General psychiatry certification requires completion of ACGME-accredited 4-year residency, passing ABPN written examination, and meeting professionalism standards. Forensic psychiatry subspecialty requires additional ACGME-accredited fellowship (1 year) and separate board examination. ABPN certification is time-limited (10-year cycle) requiring continuing certification (formerly MOC) activities.', '["MD/DO degree from accredited medical school required","Completion of 4-year ACGME-accredited psychiatry residency","Passing score on ABPN initial certification examination","Forensic psychiatry: additional 1-year ACGME-accredited fellowship","Forensic psychiatry: separate subspecialty board examination","Continuing certification: 10-year cycle with ongoing requirements","Annual requirements: CME, self-assessment, improvement in medical practice","Clinical competence must be maintained throughout certification period","Professionalism and professional standing verified by hospital/employer","Must hold valid, unrestricted medical license","Disciplinary actions may affect certification status","ABPN may revoke certification for violations of professional standards"]', '[{"section":"General Requirements","description":"MD/DO, residency, examination — three core components"},{"section":"Residency Training","description":"4-year ACGME-accredited psychiatry residency required"},{"section":"Initial Certification Exam","description":"Computer-based examination — clinical vignettes and knowledge"},{"section":"Forensic Psychiatry Fellowship","description":"1-year ACGME-accredited fellowship in forensic psychiatry"},{"section":"Forensic Psychiatry Exam","description":"Subspecialty examination — forensic evaluations, legal standards, ethics"},{"section":"Continuing Certification","description":"10-year cycle: CME, self-assessment, improvement in practice, examination"},{"section":"Professional Standing","description":"Unrestricted license, no disciplinary actions affecting competency"},{"section":"Ethics and Professionalism","description":"Adherence to AMA and APA ethical standards required"}]', '["board_certification_certificate","residency_completion_letter","fellowship_completion_letter","examination_score_report","CME_documentation","continuing_certification_portfolio","hospital_privileges_verification","license_verification"]', '["professional-ethics-standards-audit"]', 'American Board of Psychiatry and Neurology (ABPN)', 0, 1, datetime('now'), datetime('now'));

-- DSM-5 Diagnostic Standards
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_073', 'ETHICARA', 'PROFESSIONAL_STANDARD', 'US', 'American Psychiatric Association — Diagnostic and Statistical Manual of Mental Disorders, Fifth Edition, Text Revision (DSM-5-TR, 2022)', 'DSM-5-TR (APA 2022)', 'DSM-5-TR Diagnostic Standards — Classification of Mental Disorders', 'The DSM-5-TR is the authoritative diagnostic classification system for mental disorders used by clinicians, researchers, insurers, courts, and regulatory bodies in the United States. Provides standardized diagnostic criteria, clinical descriptions, and coding for all recognized mental disorders. Used in forensic evaluations, disability determinations, involuntary commitment proceedings, and competency assessments. DSM diagnosis does not imply etiology, does not establish legal competence/incompetence, and cautionary statement warns against forensic misuse.', '["Standardized diagnostic criteria for all recognized mental disorders","Multiaxial system replaced by dimensional assessments in DSM-5","Each disorder has specific inclusion and exclusion criteria","Clinical significance criterion: distress or impairment in functioning required","Cultural formulation interview for culturally-informed assessment","Must rule out substance use, medical conditions, and other mental disorders","Provisional diagnosis permitted when full criteria not yet confirmed","Specifiers for severity, course, and descriptive features","DSM diagnosis alone does not establish legal competency or incompetency","Cautionary statement: inappropriate use in forensic settings without additional information","ICD-10-CM coding system used for insurance billing and medical records","Clinician must have adequate training and licensure to render diagnosis"]', '[{"section":"Use of the Manual","description":"Intended for trained clinicians — not for self-diagnosis or legal determination"},{"section":"Cautionary Statement for Forensic Use","description":"DSM diagnosis alone insufficient for legal determinations — competency, responsibility, disability"},{"section":"Neurodevelopmental Disorders","description":"ADHD, ASD, intellectual disabilities, communication disorders"},{"section":"Schizophrenia Spectrum","description":"Schizophrenia, schizoaffective, delusional disorder, brief psychotic disorder"},{"section":"Depressive Disorders","description":"Major depressive disorder, persistent depressive, disruptive mood dysregulation"},{"section":"Anxiety Disorders","description":"GAD, panic disorder, social anxiety, specific phobias, agoraphobia"},{"section":"Trauma and Stressor-Related","description":"PTSD, acute stress disorder, adjustment disorders"},{"section":"Personality Disorders","description":"Cluster A (paranoid, schizoid, schizotypal), Cluster B (antisocial, borderline, histrionic, narcissistic), Cluster C (avoidant, dependent, OCPD)"},{"section":"Substance-Related Disorders","description":"Substance use disorders, intoxication, withdrawal by substance class"},{"section":"Neurocognitive Disorders","description":"Delirium, major/mild neurocognitive disorder (dementia), Alzheimer, vascular, Lewy body"}]', '["psychiatric_evaluation","forensic_psychiatric_report","diagnostic_assessment","treatment_plan","disability_determination","competency_evaluation","insurance_authorization","clinical_notes"]', '["professional-ethics-standards-audit"]', 'American Psychiatric Association (APA)', 0, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- ETHICARA — General Professional Standards
-- ═══════════════════════════════════════════════════════════════════════════

-- AMA Code of Medical Ethics
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_074', 'ETHICARA', 'PROFESSIONAL_STANDARD', 'US', 'American Medical Association — Code of Medical Ethics (2016, as amended)', 'AMA Code of Medical Ethics', 'AMA Code of Medical Ethics — Physician Professional Obligations', 'The AMA Code of Medical Ethics establishes ethical standards for physicians organized around core principles of beneficence, nonmaleficence, autonomy, and justice. Addresses the patient-physician relationship, consent, confidentiality, end-of-life care, organ donation, genetics, research ethics, professional self-regulation, and interprofessional relationships. While not directly enforceable as law, AMA ethical opinions are cited by medical boards, courts, and licensing bodies as the standard of professional conduct. Violation may constitute evidence of unprofessional conduct in disciplinary proceedings.', '["Principle I: Competent medical care with compassion and respect for human dignity","Principle II: Uphold standards of professionalism, be honest, report deficient physicians","Principle III: Respect the law and recognize responsibility to seek changes in unjust requirements","Principle IV: Respect patient rights, confidentiality, and privacy","Principle V: Continue study, apply knowledge, consult when indicated","Principle VI: Freedom to choose whom to serve, with whom to associate, and environment to practice","Principle VII: Recognize responsibility to participate in activities improving community health","Principle VIII: Responsibility to the patient paramount","Principle IX: Support access to medical care for all people","Informed consent: patient autonomy and shared decision-making required","Confidentiality: patient information disclosed only with consent or as required by law","Physician-assisted treatment decisions must be free of conflicts of interest"]', '[{"section":"Chapter 1: Patient-Physician Relationships","description":"Informed consent, patient rights, surrogate decision-making, termination of relationship"},{"section":"Chapter 2: Consent, Communication, Decision Making","description":"Informed consent, informed refusal, withholding information, pediatric decision-making"},{"section":"Chapter 3: Privacy, Confidentiality, Medical Records","description":"Patient confidentiality, privacy in health care, medical records access"},{"section":"Chapter 4: Genetics and Reproductive Medicine","description":"Genetic testing, reproductive choices, assisted reproduction"},{"section":"Chapter 5: Caring for Patients at End of Life","description":"Advance directives, palliative care, medically futile treatment, organ donation"},{"section":"Chapter 7: Research and Innovation","description":"Clinical research ethics, conflicts of interest in research, IRB oversight"},{"section":"Chapter 8: Physicians and the Health of the Community","description":"Public health duties, reporting obligations, expert witness testimony"},{"section":"Chapter 9: Professional Self-Regulation","description":"Peer review, impaired physicians, disciplinary action, professional competence"},{"section":"Chapter 11: Financing and Delivery of Health Care","description":"Conflicts of interest, physician financial arrangements, resource allocation"}]', '["ethics_complaint","peer_review_report","informed_consent_documentation","conflict_of_interest_disclosure","research_protocol","CME_records","hospital_bylaws","medical_staff_rules"]', '["professional-ethics-standards-audit"]', 'American Medical Association / State Medical Boards (enforcement)', 0, 1, datetime('now'), datetime('now'));

-- APA Ethical Principles of Psychologists
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_075', 'ETHICARA', 'PROFESSIONAL_STANDARD', 'US', 'American Psychological Association — Ethical Principles of Psychologists and Code of Conduct (2017 Amendment)', 'APA Ethics Code (2017)', 'APA Ethical Principles of Psychologists and Code of Conduct', 'The APA Ethics Code governs the professional conduct of psychologists including clinical, counseling, forensic, school, and research psychologists. Contains five General Principles (aspirational) and ten Ethical Standards (enforceable). Covers competence, informed consent, confidentiality, multiple relationships, fees, record-keeping, education/training, research, assessment, and therapy. Enforceable by APA (censure/expulsion), state licensing boards (license discipline), and courts (standard of care evidence). Specific standards address forensic psychology, child custody evaluations, and court-ordered assessments.', '["Standard 2: Competence — practice within boundaries of competence based on education, training, experience","Standard 3: Human Relations — avoid multiple relationships, sexual harassment, conflicts of interest","Standard 4: Privacy and Confidentiality — protect confidential information, disclosure limitations","Standard 5: Advertising and Public Statements — accuracy in professional representations","Standard 6: Record Keeping and Fees — maintain adequate records, transparent fee practices","Standard 7: Education and Training — design programs providing relevant knowledge, accurate descriptions","Standard 8: Research and Publication — informed consent, deception in research, data sharing","Standard 9: Assessment — use valid instruments, qualified interpretation, informed consent for assessment","Standard 10: Therapy — informed consent for therapy, avoid sexual relationships with patients/former patients","Forensic activities: obligation of honesty, impartiality, and competence in forensic roles","Multiple relationships: avoid if risk of impairment or exploitation","Duty to report ethics violations by colleagues when resolution not possible"]', '[{"section":"Principle A: Beneficence and Nonmaleficence","description":"Benefit those with whom they work, do no harm"},{"section":"Principle B: Fidelity and Responsibility","description":"Trustworthy relationships, professional responsibility to society"},{"section":"Principle C: Integrity","description":"Accuracy, honesty, truthfulness in science and practice"},{"section":"Principle D: Justice","description":"Fairness, equal access to contributions of psychology"},{"section":"Principle E: Respect for Rights and Dignity","description":"Respect worth and rights of all people, cultural competence"},{"section":"Standard 2.01","description":"Boundaries of Competence — practice within training and experience"},{"section":"Standard 3.05","description":"Multiple Relationships — avoid exploitation and impairment"},{"section":"Standard 4.01-4.07","description":"Confidentiality — maintaining, limits, disclosures, consultations"},{"section":"Standard 9.01-9.11","description":"Assessment — basis for opinions, use of tests, informed consent"},{"section":"Standard 10.05-10.08","description":"Sexual relationships with current/former therapy patients prohibited"}]', '["ethics_complaint","licensing_board_complaint","forensic_evaluation","psychological_assessment","research_protocol","informed_consent_form","supervision_agreement","competency_documentation"]', '["professional-ethics-standards-audit"]', 'American Psychological Association / State Licensing Boards', 0, 1, datetime('now'), datetime('now'));

-- CA BBS Licensing — MFT/LCSW/LPCC
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_076', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Bus. & Prof. Code §§ 4980-4999.129 (MFT); §§ 4996-4996.18 (LCSW); §§ 4999.10-4999.129 (LPCC)', 'BPC §§ 4980-4999.129', 'California Board of Behavioral Sciences — MFT, LCSW, and LPCC Licensing', 'The Board of Behavioral Sciences (BBS) licenses and regulates Marriage and Family Therapists (MFTs), Licensed Clinical Social Workers (LCSWs), and Licensed Professional Clinical Counselors (LPCCs) in California. Each license requires a qualifying master''s degree, supervised experience hours (3,000+ hours), and passage of licensing examinations. BBS enforces professional standards, investigates complaints, and may revoke, suspend, or impose conditions on licenses for unprofessional conduct including gross negligence, sexual misconduct, conviction of crime, and impairment.', '["MFT: Master degree with specified coursework (§ 4980.36/4980.37)","MFT: 3,000 hours supervised experience including 1,750 direct clinical contact (§ 4980.43)","MFT: Pass California Law and Ethics Exam and Clinical Exam (§ 4980.397)","LCSW: Master of Social Work from CSWE-accredited program (§ 4996.2)","LCSW: 3,000 hours supervised experience including 1,700 direct clinical contact (§ 4996.23)","LCSW: Pass California Law and Ethics Exam and Clinical Exam","LPCC: Master degree with 60 semester units specified coursework (§ 4999.33)","LPCC: 3,000 hours supervised experience (§ 4999.46)","LPCC: Pass California Law and Ethics Exam and Clinical Exam","All: License renewal every 2 years with 36 hours CME (§ 4980.54)","All: Mandated reporter obligations (CANRA, elder abuse)","All: Subject to discipline for unprofessional conduct (§ 4982 MFT, § 4992.3 LCSW, § 4999.90 LPCC)","Sexual contact with patient/former patient grounds for revocation"]', '[{"section":"4980-4980.02","description":"MFT practice defined — marriage, family, child counseling"},{"section":"4980.36-4980.37","description":"MFT education requirements — master degree, specified coursework"},{"section":"4980.43","description":"MFT supervised experience — 3,000 hours requirements"},{"section":"4982","description":"MFT grounds for discipline — unprofessional conduct enumerated"},{"section":"4996-4996.2","description":"LCSW practice defined and education requirements — MSW from CSWE program"},{"section":"4996.23","description":"LCSW supervised experience — 3,000 hours requirements"},{"section":"4992.3","description":"LCSW grounds for discipline — unprofessional conduct enumerated"},{"section":"4999.10-4999.12","description":"LPCC practice defined — professional clinical counseling"},{"section":"4999.33","description":"LPCC education requirements — 60 semester unit master degree"},{"section":"4999.46","description":"LPCC supervised experience — 3,000 hours requirements"},{"section":"4999.90","description":"LPCC grounds for discipline — unprofessional conduct enumerated"},{"section":"4980.54","description":"Continuing education — 36 hours per 2-year renewal cycle"}]', '["license_application","supervised_experience_log","examination_score_report","disciplinary_complaint","accusation_filing","license_renewal","CEU_documentation","supervision_agreement","BBS_complaint_form"]', '["professional-ethics-standards-audit"]', 'California Board of Behavioral Sciences (BBS)', 0, 1, datetime('now'), datetime('now'));

-- EMTALA — Emergency Treatment
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_077', 'ETHICARA', 'FEDERAL_STATUTE', 'US', '42 USC § 1395dd (Emergency Medical Treatment and Active Labor Act — EMTALA)', 'EMTALA / 42 USC § 1395dd', 'Emergency Medical Treatment and Active Labor Act (EMTALA) — Anti-Patient-Dumping', 'EMTALA requires Medicare-participating hospitals with emergency departments to provide a medical screening examination (MSE) to any individual who comes to the emergency department requesting treatment, regardless of ability to pay, insurance status, or citizenship. If an emergency medical condition (EMC) is found, the hospital must stabilize the patient before discharge or transfer. Applies to all patients, not just Medicare beneficiaries. Violations subject to civil monetary penalties up to $119,942 per violation, Medicare provider agreement termination, and private civil action for damages.', '["Medical screening examination (MSE) required for anyone presenting to ED (§ 1395dd(a))","MSE must be within capability of hospital — not cursory or inadequate","If emergency medical condition found, must stabilize before discharge (§ 1395dd(b))","Stabilization: no material deterioration likely during or from discharge/transfer","Transfer permitted only if: patient requests, or physician certifies medical benefits outweigh risks (§ 1395dd(c))","Receiving hospital must have available space, qualified personnel, and agree to accept transfer","Active labor: must deliver baby and placenta unless safe to transfer","Applies to ALL individuals — regardless of ability to pay, insurance, immigration status","Hospital with specialized capabilities must accept appropriate transfers (§ 1395dd(g))","On-call physicians must respond — failure is EMTALA violation","Does not require hospital to provide care beyond stabilization","Whistleblower protection for reporting EMTALA violations (§ 1395dd(i))"]', '[{"section":"1395dd(a)","description":"Medical screening examination — required for all who come to ED"},{"section":"1395dd(b)","description":"Stabilizing treatment required if emergency medical condition found"},{"section":"1395dd(c)","description":"Transfer requirements — certification, receiving hospital acceptance"},{"section":"1395dd(d)","description":"Penalties — civil monetary penalties, provider agreement termination"},{"section":"1395dd(d)(2)","description":"Private right of action — damages for personal harm from violation"},{"section":"1395dd(e)(1)","description":"Emergency medical condition defined — acute symptoms of sufficient severity"},{"section":"1395dd(e)(1)(B)","description":"Active labor — pregnant woman having contractions"},{"section":"1395dd(g)","description":"Nondiscrimination — applies regardless of ability to pay"},{"section":"1395dd(i)","description":"Whistleblower protection for EMTALA reporters"},{"section":"42 CFR 489.24","description":"CMS implementing regulations for EMTALA obligations"}]', '["medical_screening_examination","ED_medical_records","transfer_certification","EMTALA_violation_complaint","CMS_enforcement_action","civil_monetary_penalty_notice","patient_transfer_log","on_call_physician_schedule"]', '["professional-ethics-standards-audit"]', 'Centers for Medicare & Medicaid Services (CMS) / OIG', 1, 1, datetime('now'), datetime('now'));

-- Patient Access to Medical Records
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_078', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Health & Safety Code §§ 123100-123149.5 (Patient Access to Health Records)', 'H&S §§ 123100-123149.5', 'Patient Access to Medical Records — California Health Records Act', 'California law guarantees patients the right to inspect and obtain copies of their health records. Health care providers must permit inspection within 5 working days of written request and provide copies within 15 days. Reasonable cost-based fees permitted (not to exceed $0.25/page plus clerical costs). Mental health records subject to additional protections — provider may prepare a summary if disclosure would be detrimental. Applies to all health care providers, health care service plans, and contractors. More protective than federal HIPAA minimum in several respects.', '["Patient has right to inspect health records within 5 working days of written request (§ 123110)","Copies must be provided within 15 days of written request (§ 123110(b))","Fee: reasonable cost-based, not exceeding $0.25 per page plus clerical costs (§ 123110(b))","Patient representative or attorney may request with authorization (§ 123115)","Mental health records: provider may prepare summary if direct access would be detrimental (§ 123115(b))","Minor patient records: parent/guardian access subject to minor consent limitations (§ 123115(a))","Provider may not withhold records for unpaid bills for the records themselves","Records must be provided in requested format if readily producible (§ 123110(g))","Electronic health records: must provide in electronic format if maintained electronically (§ 123111)","Provider must maintain records for minimum 7 years from last date of service (§ 123145)","Patient may request amendment of records (§ 123111)","Violation: patient may bring action for damages and attorney fees (§ 123120)"]', '[{"section":"123100","description":"Definitions — health care provider, patient, health care record"},{"section":"123105","description":"Right of patients to access health records established"},{"section":"123110(a)","description":"Inspection within 5 working days of written request"},{"section":"123110(b)","description":"Copies within 15 days — fee cap $0.25/page plus clerical"},{"section":"123110(g)","description":"Records in requested format if readily producible"},{"section":"123111","description":"Electronic health records — electronic format required if available"},{"section":"123115(a)","description":"Minor patient records — parent access and minor consent exceptions"},{"section":"123115(b)","description":"Mental health records — summary if disclosure detrimental to patient"},{"section":"123120","description":"Enforcement — patient civil action for damages and attorney fees"},{"section":"123145","description":"Record retention — minimum 7 years from last date of service"},{"section":"123149.5","description":"Health information exchange — patient consent for electronic sharing"}]', '["records_request_form","authorization_to_release","medical_records","mental_health_records_summary","fee_schedule","records_amendment_request","civil_complaint_for_records_access","HIPAA_authorization"]', '["professional-ethics-standards-audit"]', 'California Superior Court / California Department of Public Health', 1, 1, datetime('now'), datetime('now'));
